import torch
import torch.nn as nn

# Transfer learning: chain rule with frozen layers
class PreTrainedFeatures(nn.Module):
    def __init__(self):
        super().__init__()
        self.features = nn.Linear(10, 8)  # "pre-trained"
    def forward(self, x):
        return torch.relu(self.features(x))

class NewHead(nn.Module):
    def __init__(self):
        super().__init__()
        self.classifier = nn.Linear(8, 2)
    def forward(self, x):
        return self.classifier(x)

# Build chain
pretrained = PreTrainedFeatures()
new_head = NewHead()

# Freeze pretrained (break chain!)
for param in pretrained.parameters():
    param.requires_grad = False  # chain rule stops here

# Forward: chain of functions
x = torch.randn(1, 10)
features = pretrained(x)  # frozen
output = new_head(features)  # trainable
loss = nn.CrossEntropyLoss()(output, torch.tensor([1]))
loss.backward()

print('Frozen layers (no gradient - chain broken):')
for name, p in pretrained.named_parameters():
    print(f'  {name}: grad = {p.grad}')

print('\nTrainable layers (gradient flows via chain rule):')
for name, p in new_head.named_parameters():
    print(f'  {name}: grad norm = {p.grad.norm():.4f}')
